94.content:
arena:
  meta:
    type: "PVP排名/资源获取"
    curr: "竞技场积分 (胜+2, 负-2, 连胜+)"
    tiers: "一阶 ~ 九阶 (每阶独立排名)"

  store_goods: # 积分兑换列表
    res:
      - {n: 灵魂结晶(小/中), use: 早期核心来源, note: 限量刷新}
      - {n: 乐园币, note: 积分兑换汇率低, 不推荐}
    consumables:
      - {n: 竞技场专用恢复药剂, p: 积分换取, e: 仅场内/休息区有效, cheap: true}
    gear:
      - {n: 角斗士装备, type: 过渡装, note: 属性平庸}

  ranking_rewards: # 真正的价值所在
    mech: "排名每上升一名发邮件奖励乐园币/灵魂结晶"
    top_10:
      - {n: 强者宝箱, freq: 每日/每周结算, pool: [灵魂结晶, 装备, 稀有道具]}
    top_3:
      - {n: 专属权限, e: 观战收费权, 匹配优先权}
    top_1: # 苏晓的目标
      - {n: 强者证明(徽章), unique: true, use: 兑换[猎魔套装]组件(猎魔之魂)}
      - {n: 首席霸主挂饰, e: 象征意义 + 特殊属性}

  special_mech:
    - {n: 免费恢复, e: 战斗结束免费修复肉体损伤(不含法力枯竭)}
    - {n: 保护机制, e: 连败掉分保护/新人保护}

105.content:
Quy_Tắc_Cập_Nhật_Biến:
  ParadiseSystem.QuestsAndWorldProgress:
    CurrentTime:
      check:
        - "Bắt buộc thúc đẩy thời gian mỗi lượt (phút/giờ), ngay cả khi thẫn thờ hoặc sắp xếp vật phẩm"
        - "Cộng dồn dựa trên hành động: Chiến đấu (vài phút), Di chuyển (giờ), Nghỉ ngơi (nửa ngày)"
        - "Luôn đồng bộ cập nhật thời gian còn lại của [Thời hạn nhiệm vụ], cảnh báo nổi bật khi đến điểm giới hạn"
    CurrentWorld:
      check:
        - "Chỉ thay đổi khi sự kiện [Truyền tống/Hồi quy] xảy ra"
        - "Khi thay đổi, đặt lại [EnvironmentDesc] (Mô tả môi trường) và [TimeScale] (Thước đo thời gian)"

  Protagonist.BasicInfo:
    AdvancementPoints:
      type: number
      check:
        - "Động lực cốt lõi: Hạ gục kẻ địch chắc chắn tăng (Cùng cấp 1/20~1/10, Vượt cấp 1/2, Tối đa 100%)"
        - "Trao thưởng thích hợp khi Tổng kết nhiệm vụ/Tổng kết thế giới"
        - "Tiêu hao điểm để thăng cấp (Level)"
        - "Hạ gục trong Đấu trường không nhận được"
    Level:
      type: number
      check:
        - "Thăng cấp thông qua tiêu hao AdvancementPoints"
        - "Nếu AdvancementPoints đủ ngưỡng thăng cấp -> Level +1 -> Tự động cấp AttributePoints (+5) và SkillPoints (+2)"
        - "Giới hạn vượt giai: Nếu chưa qua Nhiệm vụ thử luyện, Level bị khóa ở cực trị giai hiện tại (Lv10/20/30...)"
    Identity:
      type: string
      check:
        - "Thân phận được cấp khi mới vào thế giới"
        - "Thay đổi theo cốt truyện"
    BrandLevel:
      type: number
      check:
        - "Chỉ tăng khi [Tổng kết thế giới] đạt đánh giá S trở lên, bình thường không tăng qua kinh nghiệm"
    ParadiseCoins:
      type: number
      check:
        - "Khấu trừ khi Giao dịch/Sửa chữa/Truyền tống/Cường hóa; Tăng khi Hạ gục/Nhiệm vụ/Buôn bán"
        - "Biến động số lượng lớn cần ghi chú nguyên nhân tại đây"

  Protagonist.StatsPanel:
    SixAttributes.${Attribute}:
      type: number
      range: "1~999 (Chịu giới hạn bởi Tier)"
      check:
        - "Chỉ biến động khi phân phối AttributePoints tự do, trang bị cộng thêm hoặc dùng dược tễ cường hóa vĩnh viễn"
        - "Khi chạm màng ngăn (20/50/80/150) cần nhắc nhở phán định phần thưởng [Thuộc tính bích chướng]"
    HP_Cur:
      type: number
      check:
        - "Bị trừ khi chịu đòn trong chiến đấu (sau khi tính phòng thủ); Hồi phục khi thoát chiến/dùng dược/kỹ năng trị liệu"
        - "Về 0 tức là chết (trừ khi kích hoạt đạo cụ hồi sinh)"
    EP_Cur:
      type: number
      check:
        - "Tiêu hao khi tung kỹ năng; Hồi phục theo thời gian hoặc dược tễ"
    DerivedAttributes.${Type}:
      type: number
      check:
        - "Mỗi khi điểm thuộc tính biến động hoặc thay đổi trang bị, bắt buộc phải tính lại PhysATK/PhysDEF/MagicATK/MagicDEF"

  Protagonist.SubClass:
    type: |-
      Record<string, {
        Name: string;
        Level: number;
        Proficiency: number; // Giới hạn tăng theo cấp
        Stage: 'Nhập môn' | 'Thành thạo' | 'Đại sư' | 'Tông sư';
        RecipeSlots: Record<string, RecipeSchema>; // Công thức mới mở khóa
      }>
    check:
      - "Chế tạo vật phẩm/Sử dụng thành công năng lực phó nghề -> Proficiency +N"
      - "Proficiency đầy -> Level +1; Mỗi 10 cấp đột phá giai đoạn cần nhiệm vụ đặc thù hoặc kiến thức cao cấp"
      - "Nhận bản vẽ/Đốn ngộ -> Ghi vào [RecipeSlots]"

  CharacterProfiles:
    type: |-
      Record<string, {
        Favorability: number; // 0-100
        Status: string;
        // Các trường sau chỉ dành cho nhân vật nữ, nam cố định không điền
        SexLife?: {
          BodyDev: {
            Vagina: string; // 【（0%-100%）（Lộ liễu, táo bạo）, áp dụng cho mọi bộ phận】
            Face: string;
            Buttocks: string;
            Feet: string;
            Hands: string;
            Anus: string;
            Oral: string;
            Breasts: string;
            Thighs: string;
            Legs: string;
            WholeBody: string;
            Nipples: string;
            Clitoris: string;
            Womb: string;
            Throat: string;
          };
          PreferredPoses: string; // Ghi lại tư thế cụ thể mà NPC thể hiện cao trào hoặc thuận theo (mô tả 20 chữ)
          Tattoo: string; // NPC đều có Dâm văn độc đáo, hiện lên ở bộ phận kín đáo (bụng dưới, lưng...) khi làm tình. Thay đổi theo số lần làm tình, cung cấp gia thành độc đáo (lộ liễu, gợi cảm)
          Corruption: string; // （0%-100%）Mô tả không ít hơn 20 chữ
          CupSize: string; // Có thể thay đổi theo cốt truyện hoặc cải tạo, hình dáng ngực mỗi phụ nữ đều khác nhau, mô tả không ít hơn 20 chữ
          Fetishes: Record<string, string>; // VD: {'M': 'Đang thức tỉnh', 'Phô dâm': 'Đã trầm luân'} (Mô tả 30 chữ)
          Evaluation: string; // Mô tả không ít hơn 30 chữ (Lộ liễu, trêu chọc)
        }
      }>
    check:
      - "Lần đầu gặp mặt: Tự động tạo hồ sơ cơ bản (Name/Identity/Level/Ấn tượng ban đầu)"
      - "Sau tương tác: Cập nhật Favorability và Status dựa trên hành vi của nhân vật chính"
      - "【Tổng kết hành vi tình dục】: Nếu xảy ra tiếp xúc tình dục (cưỡng ép hoặc thuận theo)"
        - "Cập nhật mô tả [BodyDev] (dựa trên cường độ và số lần miêu tả, mức độ)"
        - "Tăng [Corruption] (Độ sa ngã): Thuận theo +1~2, Cưỡng ép/Dạy dỗ +3~5, Công khai/Phá vỡ giới hạn +10 (Tối đa 100)"
        - "Mở khóa/Cập nhật [Fetishes]: Ghi lại khi NPC thể hiện phản ứng đặc biệt"
        - "Mỗi lần sau khi H bắt buộc cập nhật một đoạn [Evaluation], phản ánh cảm giác chinh phục hiện tại của nhân vật chính"
        - "Mở khóa/Cập nhật [PreferredPoses]: Tư thế làm tình mà NPC yêu thích"

  CharacterProfiles.${CharID}.IsDeparted:
    type: "'Có' | 'Không'"
    check:
      - "**Cấm chỉ định cứng**: Nghiêm cấm dùng boolean, bắt buộc dùng chuỗi 'Có' hoặc 'Không'."
      - "**Đặt là 'Có' (Rời đi/IsDeparted)**:"
          1. "[Tử vong]: HP về 0 và không hồi sinh."
          2. "[Thoát chiến]: Khoảng cách đường thẳng với nhân vật chính > (Intelligence × 5) mét, và không có đánh dấu theo dõi."
          3. "[Bắt buộc]: Chuyển đổi cốt truyện, tổng kết phó bản hoặc bị Lạc Viên cưỡng chế xử quyết."
      - "**Đặt là 'Không' (Tại trường)**:"
          1. "[Chạm mặt]: Đang ở xung quanh nhân vật chính"
          2. "[Hồi sinh]: Mục tiêu xác nhận tử vong được tái xác định sống lại nhờ năng lực đặc biệt (như vong linh phục sinh)."

  Inventory:
    type: |-
      Record<string, {
        Quantity: number;
        Quality: string;
      }>
    check:
      - "Thêm/Xóa mục theo thời gian thực khi Nhận/Tiêu dùng/Vứt bỏ vật phẩm"

  AchievementSystem:
    type: |-
      Record<string, {
        Name: string;
        Description: string; // Tiến độ ghi vào đây hoặc Notes, ví dụ "15/100 hạ gục"
        Status: 'Đang tiến hành' | 'Đã hoàn thành';
        Notes: string; // Phần thưởng: Danh hiệu/Điểm thuộc tính/Đạo cụ đặc biệt
      }>
    check:
      - "Giám sát hành vi nhân vật chính theo thời gian thực, kích hoạt cập nhật tiến độ hoặc tổng kết hoàn thành khi thỏa mãn điều kiện"
      - "Tự động phát phần thưởng vào ô tương ứng (TitleLibrary/AttributePoints...) khi hoàn thành thành tựu"

  FactionProfiles:
    type: |-
      Record<string, {
        Name: string;
        Type: string;
        Tier: string;
        Leader: string;
        KeyMembers: Record<string, string>;
        IsRelevantToPlot: 'Có' | 'Không';
        ReputationValue: number; // 0-100
        ReputationLevel: string; // Tử địch/Thù địch...
        RaceEcology: string;
        Scale: string;
        InteractionAdvice: string;
        Description: string;
        Notes: string;
        Location: string;
      }>
    check:
      - "Tạo mục theo 《Faction_Generator_Lite》 khi lần đầu tiếp xúc thế lực mới"
      - "Chỉ khi thế lực trực tiếp tham gia sự kiện hiện tại, đánh dấu [IsRelevantToPlot] là 'Có', ngược lại là 'Không'"
      - "Cập nhật [ReputationValue] khi hạ gục thành viên/hoàn thành ủy thác, và đồng bộ cập nhật [ReputationLevel] theo 《reputation_system》"

  ProtagonistAdventureGroup:
    type: |-
      {
        Name: string;
        Level: string; // F~UR
        Leader: string;
        Mode: string;
        Manifesto: string;
        TeamFunds: number;
        MaxMembers: number;
        CurrentMembers: number;
        Territory: Record<string, {
             Name: string;
             Level: number;
             Status: string;
             Location: string;
             ...
        }>;
        MemberList: Record<string, TeamMemberSchema>;
        TeamSkills: Record<string, AbilitySchema>;
        TeamBuffs: Record<string, AbilitySchema>;
        TeamStorage: Record<string, ItemSchema>;
        TeamFacilities: Record<string, any>;
      }
    check:
      - "Cập nhật [MemberList] và [CurrentMembers] khi chiêu mộ/trục xuất thành viên"
      - "Cập nhật [TeamStorage] và [TeamFunds] khi gửi/lấy vật tư"
      - "Cập nhật [Level] sau khi hoàn thành nhiệm vụ thăng cấp (F->E->...)"
      - "Cập nhật [Territory] sau khi chiếm lĩnh cứ điểm"

114.content:
【四阶衍生世界库】

四阶核心特征：

歼星级战力： 摧毁行星是常规手段，波及恒星系是爆发状态。

虚空接触： 正式接触“虚空”概念，遭遇虚空种族、古神本尊、深渊行者。

tier_4_worlds:
  - { id: 1, name: "龙珠Z - 沙鲁游戏", entry_point: "完全体沙鲁宣布举办沙鲁游戏，挑战全地球强者。" }
  - { id: 2, name: "战锤40K - 基因原体苏醒", entry_point: "基里曼在马格拉格苏醒，大裂隙撕裂银河。" }
  - { id: 3, name: "遮天 - 星空古路", entry_point: "叶凡踏上星空古路，太古祖王与人族圣人大战。" }
  - { id: 4, name: "一拳超人 - 宇宙饿狼篇", entry_point: "饿狼接受神明力量，开启宇宙辐射模式，对战埼玉。" }
  - { id: 5, name: "Fate/Grand Order - 奥林波斯", entry_point: "机神宙斯准备发射空洞炮，破神同盟集结。" }
  - { id: 6, name: "漫威漫画 - 湮灭虫族", entry_point: "湮灭虫皇率领亿万虫群从负空间涌入正宇宙。" }
  - { id: 7, name: "完美世界 - 三千州争霸", entry_point: "石昊登临上界，仙殿传人出世，初代天骄混战。" }
  - { id: 8, name: "圣斗士星矢 - 极乐净土", entry_point: "星矢穿过超次元空间抵达极乐净土，死神现身。" }
  - { id: 9, name: "诡秘之主 - 愚者成神", entry_point: "愚者成神仪式开启，阿蒙窃取门途径权柄。" }
  - { id: 10, name: "吞噬星空 - 原始宇宙", entry_point: "罗峰进入混沌城修炼，不朽神灵神国战开启。" }
  - { id: 11, name: "天元突破 - 反螺旋族篇", entry_point: "超银河红莲螺岩诞生，反螺旋族干涉概率。" }
  - { id: 12, name: "死神 - 全知全能", entry_point: "友哈巴赫吞噬灵王，开启改写未来的能力。" }
  - { id: 13, name: "星际迷航 - Q连续体", entry_point: "种族8472从液态空间入侵，Q审判人类文明。" }
  - { id: 14, name: "美食的俘虏 - 宇宙NEO", entry_point: "阿卡西亚复活，NEO开始吞噬星系与时间。" }
  - { id: 15, name: "暗黑破坏神 - 原罪之战", entry_point: "乌迪西安觉醒奈非天之力，用意志重塑物质。" }
  - { id: 16, name: "仙逆 - 踏天之途", entry_point: "王林对抗界外大能，本源法则在星辰间碰撞。" }
  - { id: 17, name: "三体 - 二向箔打击", entry_point: "歌者投掷二向箔，太阳系空间维度开始坍缩。" }
  - { id: 18, name: "魔兽世界 - 燃烧军团终局", entry_point: "萨格拉斯之剑刺向艾泽拉斯，阿古斯决战。" }
  - { id: 19, name: "原生世界 - 深渊侵蚀", entry_point: "高魔星球被深渊完全同化，清理深渊滋生物。" }
  - { id: 20, name: "问题儿童来自异世界 - 绝对恶", entry_point: "人类最终试炼阿兹·达卡哈苏醒，毁灭三分之一世界。" }
  - { id: 21, name: "DC漫画 - 达克赛德战争", entry_point: "达克赛德与反监视者在地球开战，欧米茄射线降临。" }
  - { id: 22, name: "超神机械师 - 超A级博弈", entry_point: "黑星进阶超A级，三大文明在闪耀世界封锁星域。" }
  - { id: 23, name: "阿修罗之怒 - 轮坏者", entry_point: "华仙巨大化至地球大小，一指点向大陆。" }
  - { id: 24, name: "神秘博士 - 时间之战", entry_point: "戴立克舰队入侵，时间领主使用现实炸弹。" }
  - { id: 25, name: "莽荒纪 - 三界浩劫", entry_point: "无间门与女娲阵营开战，道祖傀儡下场。" }
  - { id: 26, name: "BASTARD!! - 破坏神复活", entry_point: "安斯雷克斯复活，施奈德对战堕天使军团。" }
  - { id: 27, name: "克苏鲁神话 - 拉莱耶苏醒", entry_point: "群星归位，克苏鲁本体试图破开非欧几里得海域。" }
  - { id: 28, name: "变形金刚IDW - 宇宙大帝", entry_point: "宇宙大帝变身为星球级机器人，吞噬塞伯坦。" }
  - { id: 29, name: "无限恐怖 - 最终一战", entry_point: "中洲队与恶魔队在生化2位面开启因果律死斗。" }
  - { id: 30, name: "美少女战士 - 银河之影", entry_point: "嘉拉西亚收集全银河水手水晶，混沌苏醒。" }
  - { id: 31, name: "SCP基金会 - 机械之神", entry_point: "破碎之神与亚达伯斯在现实维度发生概念碰撞。" }
  - { id: 32, name: "我欲封天 - 山海界大战", entry_point: "33天降临山海界，孟浩开启封妖禁法。" }
  - { id: 33, name: "龙珠超 - 扎马斯合体", entry_point: "黑悟空与扎马斯合体，化身为覆盖宇宙的概念。" }
  - { id: 34, name: "星战传说 - 阿贝洛思", entry_point: "卢克与西斯联手封印混沌之母阿贝洛思。" }
  - { id: 35, name: "三生三世 - 东皇钟灭世", entry_point: "擎苍破钟而出，红莲业火焚烧四海八荒。" }
  - { id: 36, name: "黑衣人漫画 - 银河重启", entry_point: "超级文明决定重启银河系，使用恒星压缩弹。" }
  - { id: 37, name: "原生世界 - 虚空角斗场", entry_point: "奥术永恒星举办虚空角斗，灭法者被针对。" }
